<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Faculty';
if(isset($_GET['delete'])){executeSql('DELETE FROM faculty WHERE id=?',[(int)$_GET['delete']]); header('Location: index.php'); exit;}
if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf();$id=(int)($_POST['id']??0);$p=[post('full_name'),post('email'),post('department'),(float)post('salary','0'),post('subject'),post('phone')]; if($id){$p[]=$id; executeSql('UPDATE faculty SET full_name=?,email=?,department=?,salary=?,subject=?,phone=? WHERE id=?',$p);} else {executeSql('INSERT INTO faculty(full_name,email,department,salary,subject,phone) VALUES (?,?,?,?,?,?)',$p);} header('Location: index.php'); exit;}
$edit=get('edit')?fetchOne('SELECT * FROM faculty WHERE id=?',[(int)get('edit')]):null; $rows=fetchAll('SELECT * FROM faculty ORDER BY id DESC'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="id" value="<?=$edit['id']??0?>"><div class="col"><input name="full_name" class="form-control" placeholder="Name" value="<?=e($edit['full_name']??'')?>" required></div><div class="col"><input name="email" class="form-control" type="email" placeholder="Email" value="<?=e($edit['email']??'')?>" required></div><div class="col"><input name="department" class="form-control" placeholder="Department" value="<?=e($edit['department']??'')?>" required></div><div class="col"><input name="salary" type="number" class="form-control" value="<?=e((string)($edit['salary']??0))?>"></div><div class="col"><input name="subject" class="form-control" placeholder="Subject" value="<?=e($edit['subject']??'')?>"></div><div class="col"><input name="phone" class="form-control" placeholder="Phone" value="<?=e($edit['phone']??'')?>"></div><div class="col"><button class="btn btn-primary">Save</button></div></form><hr><table class="table"><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['department'])?></td><td><?=number_format((float)$r['salary'],2)?></td><td><a href="?edit=<?=$r['id']?>">Edit</a> | <a href="?delete=<?=$r['id']?>" onclick="return confirm('Delete?')">Delete</a></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
